<script setup lang="ts">import { ref } from 'vue'; import { useMediaStore } from '../store'; const store = useMediaStore(); const title = ref(''); const format = ref('Series'); const message = ref(''); const submit = () => { if (title.value.trim().length < 3) { message.value = 'Add a descriptive title.'; return } store.publish(title.value, format.value); title.value = ''; message.value = 'Draft created.' }</script>
<template><main class="page"><span class="eyebrow">Publisher workspace</span><h1>Creator studio</h1><p>Prepare original programmes for editorial review.</p><div class="studio"><form @submit.prevent="submit"><h2>New programme</h2><label>Working title<input v-model="title" /></label><label>Format<select v-model="format"><option>Series</option><option>Feature</option><option>Documentary</option></select></label><button>Create draft</button><p role="status">{{ message }}</p></form><section><h2>Production slate</h2><div v-for="item in store.published" :key="item.title" class="slate"><div><b>{{ item.title }}</b><small>{{ item.format }}</small></div><span>{{ item.status }}</span></div></section></div></main></template>
